module divide_by_8(
    input clk,
    input rst,
    output reg [2:0] q
);
    reg [2:0] div_count;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            div_count <= 3'b000;
            q <= 3'b000;
        end else begin
            if (div_count == 3'b111) begin
                div_count <= 3'b000;
                q <= q + 1;
            end else begin
                div_count <= div_count + 1;
            end
        end
    end
endmodule
